      result = data;  // Narrowed to string
    }
  } else {
    result = data;  // Not narrowed, still string | number
  }

  // After the if/else:
  // TypeScript infers result type from all branches
  // result is: string | number (union of narrowed and non-narrowed paths)

  if (typeof result === 'string') {
